          },
        ],
      };
      const result = processScenario(scenario);
      expect(result.results[0].premium).toBe(49);
    });
    it("returns 165G for a sword and amulet (100+60 base + 5G fee)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
